from agno.agent import Agent
from agno.tools import DuckDuckGoSearch, Wikipedia

fact_checker = Agent(
    name="FactChecker",
    model="gpt-4o",
    tools=[DuckDuckGoSearch(), Wikipedia()],
    instructions="Verify every factual claim. Flag hallucinations. Cite sources."
)

def generate_verified_content(topic: str):
    draft = content_agent.run(topic)
    verification = fact_checker.run(f"Verify this content: {draft.content}")
    if "APPROVED" in verification.content:
        return draft
    else:
        return content_agent.run(f"Rewrite fixing: {verification.content}")

verified_post = generate_verified_content("AI ethics 2024")

