from vex import verify
from agno.agent import Agent

@verify(checks=["brand_consistency"])
def generate_brand_content(topic: str, style_guide: str):
    """Vex automatically validates brand voice against style_guide embedding"""
    return content_agent.run(f"Write about {topic} using brand voice: {style_guide}")

# Vex blocks execution if brand voice fails
safe_content = generate_brand_content(
    "summer marketing campaign",
    "Casual, energetic tone. Short sentences. Emojis ✅"
)
print(safe_content.content)
